import{_ as o,o as a,c as d,a5 as t}from"./chunks/framework.DYHZIppx.js";const g=JSON.parse('{"title":"ARD-0000 — 아키텍처 진단 및 초기 설계 방향","description":"","frontmatter":{},"headers":[],"relativePath":"decision-log/ard-0000.md","filePath":"decision-log/ard-0000.md"}'),c={name:"decision-log/ard-0000.md"};function r(n,e,i,s,l,h){return a(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="ard-0000-—-아키텍처-진단-및-초기-설계-방향" tabindex="-1">ARD-0000 — 아키텍처 진단 및 초기 설계 방향 <a class="header-anchor" href="#ard-0000-—-아키텍처-진단-및-초기-설계-방향" aria-label="Permalink to &quot;ARD-0000 — 아키텍처 진단 및 초기 설계 방향&quot;">​</a></h1><p><strong>날짜:</strong> 2026-03-18<br><strong>상태:</strong> 완료 (전체 반영)</p><hr><h2 id="배경" tabindex="-1">배경 <a class="header-anchor" href="#배경" aria-label="Permalink to &quot;배경&quot;">​</a></h2><p>프로젝트를 NPM 라이브러리로 공개하기 전, 현재 구조의 문제점을 체계적으로 진단하고 개선 방향을 수립했습니다. 이 문서는 그 진단 결과와 결정 사항을 기록합니다.</p><h2 id="진단된-문제" tabindex="-1">진단된 문제 <a class="header-anchor" href="#진단된-문제" aria-label="Permalink to &quot;진단된 문제&quot;">​</a></h2><h3 id="_1-디렉토리-파편화" tabindex="-1">1. 디렉토리 파편화 <a class="header-anchor" href="#_1-디렉토리-파편화" aria-label="Permalink to &quot;1. 디렉토리 파편화&quot;">​</a></h3><p>핵심 도메인 모델(<code>DomainState</code>, <code>DomainVO</code>, <code>DomainPipeline</code>)이 <code>src/</code> 외부인 루트의 <code>model/</code> 디렉토리에 위치해 있었고, 플러그인도 별도의 <code>plugin/</code> 디렉토리에 분리되어 있었습니다.</p><p>이는 번들러의 Entry Point 추적을 복잡하게 만들고 Tree-shaking 효율을 떨어뜨립니다. <code>tsconfig.json</code> 의 <code>include</code> 배열이 <code>src/**/*</code>, <code>model/**/*</code>, <code>plugin/**/*</code> 세 곳을 따로 가리키는 것이 파편화의 증거입니다.</p><p><strong>결정:</strong> 모든 소스를 <code>src/</code> 하위로 통합. <code>model/</code> → <code>src/domain/</code>, <code>plugin/</code> → <code>src/plugins/</code>, <code>src/handler/</code> → <code>src/network/</code>. 진입점 파일명을 컨벤션에 맞게 <code>rest-domain-state-manager.js</code> → <code>index.js</code> 로 변경.</p><h3 id="_2-http-메서드-분기-로직의-결함" tabindex="-1">2. HTTP 메서드 분기 로직의 결함 <a class="header-anchor" href="#_2-http-메서드-분기-로직의-결함" aria-label="Permalink to &quot;2. HTTP 메서드 분기 로직의 결함&quot;">​</a></h3><p>당시 <code>save()</code> 의 분기 로직은 <code>changeLog.length &gt; 0 이면 PATCH, 아니면 PUT</code> 이었습니다. 이는 두 가지 의미론적 오류를 내포합니다.</p><p>첫째, <code>changeLog</code> 는 RFC 6902 감사 이력이지 &quot;전체 교체 필요 여부&quot;의 판단 기준이 아닙니다. 둘째, 필드의 90%가 변경된 경우에도 항상 PATCH를 보내는 것은 비효율적입니다.</p><p><strong>결정:</strong> <code>_dirtyFields: Set&lt;string&gt;</code> 를 새로 도입. 변경된 최상위 키 비율(<code>dirtyRatio = dirtyFields.size / totalFields</code>)을 기준으로 <code>DIRTY_THRESHOLD = 0.7</code> 이상이면 PUT, 미만이면 PATCH로 분기. 자세한 내용은 <a href="/rest-domain-state-manager/architecture/http-routing">HTTP 자동 라우팅</a> 참고.</p><h3 id="_3-순환-참조-해소-방식" tabindex="-1">3. 순환 참조 해소 방식 <a class="header-anchor" href="#_3-순환-참조-해소-방식" aria-label="Permalink to &quot;3. 순환 참조 해소 방식&quot;">​</a></h3><p><code>DomainState</code> 와 <code>DomainPipeline</code> 의 상호 참조를 해소하기 위해 <code>globalThis.__DSM_DomainPipeline</code> 전역 변수를 사용하고 있었습니다. 이는 설계가 꼬였다는 것을 스스로 증명하는 코드입니다.</p><p><strong>결정:</strong> Constructor Injection 패턴 채택. <code>index.js</code> 진입점에서 <code>DomainState.PipelineConstructor = DomainPipeline</code> 을 한 번 할당. 두 모듈이 서로를 직접 import하지 않으며, 전역 오염 없음.</p><h3 id="_4-v8-최적화-부재" tabindex="-1">4. V8 최적화 부재 <a class="header-anchor" href="#_4-v8-최적화-부재" aria-label="Permalink to &quot;4. V8 최적화 부재&quot;">​</a></h3><p><code>DomainVO</code> 없이 서버 응답을 직접 빈 객체에 동적 할당하면 V8 Hidden Class가 계속 전이되어 Inline Caching이 무력화됩니다. 또한 Proxy 트랩 내부에서 원시 접근(<code>target[prop]</code>)을 사용하여 상속 구조가 복잡한 객체에서 Context Loss 버그 가능성이 있었습니다.</p><p><strong>결정:</strong> <code>DomainVO.fields</code> 로 프로퍼티 구조 사전 선언. Proxy 트랩 내부 전체를 <code>Reflect</code> API로 교체. WeakMap 기반 Lazy Proxying 도입.</p><h2 id="영향-범위" tabindex="-1">영향 범위 <a class="header-anchor" href="#영향-범위" aria-label="Permalink to &quot;영향 범위&quot;">​</a></h2><p>이 결정들은 Milestone 1(Dirty Checking), Milestone 2(디렉토리 재구조화), 그리고 이후 전체 아키텍처에 지속적인 영향을 미쳤습니다.</p>',22)])])}const m=o(c,[["render",r]]);export{g as __pageData,m as default};
